  // ---------- about ----------
  'about.hero.weAreFramers': { pt: 'somos os framers', es: 'somos los framers', fr: 'nous sommes les framers', de: 'wir sind die framers', ja: '私たちは framers です', ko: '우리는 framers입니다', zh: '我们是 framers' },
  'about.hero.title': { pt: 'Sobre AgentOS', es: 'Sobre AgentOS', fr: 'À propos d’AgentOS', de: 'Über AgentOS', ja: 'AgentOS について', ko: 'AgentOS 소개', zh: '关于 AgentOS' },
  'about.mission.title': { pt: 'Nossa Missão', es: 'Nuestra Misión', fr: 'Notre Mission', de: 'Unsere Mission', ja: '私たちのミッション', ko: '우리의 미션', zh: '我们的使命' },
  'about.mission.p1': { pt: 'Estamos construindo o runtime de agentes de IA mais avançado para desenvolvedores que querem criar sistemas inteligentes e adaptativos sem comprometer controle, segurança ou desempenho.', es: 'Estamos construyendo el runtime de agentes de IA más avanzado para desarrolladores que quieren crear sistemas inteligentes y adaptativos sin comprometer el control, la seguridad o el rendimiento.', fr: 'Nous construisons le runtime d’agents IA le plus avancé pour les développeurs qui veulent créer des systèmes intelligents et adaptatifs sans compromettre le contrôle, la sécurité ou les performances.', de: 'Wir bauen die fortschrittlichste KI-Agent-Runtime für Entwickler, die intelligente, adaptive Systeme erstellen möchten, ohne Kompromisse bei Kontrolle, Sicherheit oder Performance einzugehen.', ja: '私たちは、コントロール、安全性、パフォーマンスを犠牲にすることなく、インテリジェントで適応的なシステムを構築したい開発者のために、最も先進的な AI エージェントランタイムを構築しています。', ko: '우리는 제어, 안전, 성능을 타협하지 않고 지능적이고 적응적인 시스템을 만들고자 하는 개발자를 위해 가장 진보된 AI 에이전트 런타임을 구축하고 있습니다.', zh: '我们正在为希望在不牺牲控制、安全或性能的前提下创建智能、自适应系统的开发者打造最先进的 AI 智能体运行时。' },
  'about.mission.p2': { pt: 'AgentOS combina orquestração de IA de ponta com infraestrutura pronta para produção, permitindo que desenvolvedores construam desde simples chatbots até sistemas multi-agente complexos com {span} arquitetura de memória.', es: 'AgentOS combina orquestación de IA de vanguardia con infraestructura lista para producción, permitiendo a los desarrolladores construir desde simples chatbots hasta sistemas multi-agente complejos con arquitectura de memoria {span}.', fr: 'AgentOS combine une orchestration IA de pointe avec une infrastructure prête pour la production, permettant aux développeurs de construire de simples chatbots aux systèmes multi-agents complexes avec une architecture de mémoire {span}.', de: 'AgentOS kombiniert modernste KI-Orchestrierung mit produktionsreifer Infrastruktur und ermöglicht Entwicklern, von einfachen Chatbots bis zu komplexen Multi-Agenten-Systemen mit {span}-Memory-Architektur zu bauen.', ja: 'AgentOS は最先端の AI オーケストレーションと本番対応のインフラを組み合わせ、開発者がシンプルなチャットボットから {span} メモリアーキテクチャを備えた複雑なマルチエージェントシステムまで構築できるようにします。', ko: 'AgentOS는 최첨단 AI 오케스트레이션과 프로덕션 준비된 인프라를 결합하여 개발자가 단순한 챗봇부터 {span} 메모리 아키텍처를 갖춘 복잡한 멀티 에이전트 시스템까지 구축할 수 있게 합니다.', zh: 'AgentOS 将前沿 AI 编排与生产就绪的基础设施相结合,使开发者能够构建从简单聊天机器人到具有 {span} 记忆架构的复杂多智能体系统。' },
  'about.team.title': { pt: 'A Equipe', es: 'El Equipo', fr: 'L’Équipe', de: 'Das Team', ja: 'チーム', ko: '팀', zh: '团队' },
  'about.team.description': { pt: 'AgentOS é desenvolvido pela <manicLink>Manic Agency LLC</manicLink> e pela equipe da <frameLink>Frame.dev</frameLink>. Também construímos a <wildsLink>Wilds.ai</wildsLink>, uma plataforma de jogos AI-native alimentada por AgentOS. Somos uma equipe distribuída de engenheiros, designers e pesquisadores de IA apaixonados por tornar a IA avançada acessível a todos os desenvolvedores.', es: 'AgentOS es desarrollado por <manicLink>Manic Agency LLC</manicLink> y el equipo de <frameLink>Frame.dev</frameLink>. También construimos <wildsLink>Wilds.ai</wildsLink>, una plataforma de juegos AI-native impulsada por AgentOS. Somos un equipo distribuido de ingenieros, diseñadores e investigadores de IA apasionados por hacer la IA avanzada accesible a todos los desarrolladores.', fr: 'AgentOS est développé par <manicLink>Manic Agency LLC</manicLink> et l’équipe de <frameLink>Frame.dev</frameLink>. Nous construisons également <wildsLink>Wilds.ai</wildsLink>, une plateforme de jeu AI-native propulsée par AgentOS. Nous sommes une équipe distribuée d’ingénieurs, de designers et de chercheurs en IA passionnés par l’idée de rendre l’IA avancée accessible à tous les développeurs.', de: 'AgentOS wird von <manicLink>Manic Agency LLC</manicLink> und dem Team von <frameLink>Frame.dev</frameLink> entwickelt. Wir bauen außerdem <wildsLink>Wilds.ai</wildsLink>, eine KI-native Gaming-Plattform, die von AgentOS angetrieben wird. Wir sind ein verteiltes Team aus Ingenieuren, Designern und KI-Forschern, mit der Mission, fortgeschrittene KI für alle Entwickler zugänglich zu machen.', ja: 'AgentOS は <manicLink>Manic Agency LLC</manicLink> と <frameLink>Frame.dev</frameLink> のチームによって開発されています。また、AgentOS を活用した AI ネイティブなゲーミングプラットフォームである <wildsLink>Wilds.ai</wildsLink> も構築しています。私たちはエンジニア、デザイナー、AI 研究者からなる分散チームで、先進的な AI をすべての開発者がアクセスできるものにすることに情熱を注いでいます。', ko: 'AgentOS는 <manicLink>Manic Agency LLC</manicLink>와 <frameLink>Frame.dev</frameLink> 팀이 개발합니다. 또한 AgentOS로 구동되는 AI 네이티브 게이밍 플랫폼인 <wildsLink>Wilds.ai</wildsLink>도 만들고 있습니다. 우리는 엔지니어, 디자이너, AI 연구자로 구성된 분산 팀이며, 모든 개발자가 고급 AI에 접근할 수 있도록 만드는 데 열정을 쏟고 있습니다.', zh: 'AgentOS 由 <manicLink>Manic Agency LLC</manicLink> 和 <frameLink>Frame.dev</frameLink> 团队开发。我们还构建了由 AgentOS 提供支持的 AI 原生游戏平台 <wildsLink>Wilds.ai</wildsLink>。我们是一支由工程师、设计师和 AI 研究人员组成的分布式团队,致力于让先进的 AI 对所有开发者都触手可及。' },
