  'about.team.joinUs': { pt: 'Junte-se a nós para construir o futuro de agentes autônomos.', es: 'Únete a nosotros para construir el futuro de los agentes autónomos.', fr: 'Rejoignez-nous pour construire l’avenir des agents autonomes.', de: 'Komm dazu und gestalte mit uns die Zukunft autonomer Agenten.', ja: '自律エージェントの未来を共に築きましょう。', ko: '자율 에이전트의 미래를 함께 만들어가요.', zh: '加入我们,共同构建自主智能体的未来。' },
