  'about.license.extensionsDesc': { pt: 'Agentes, extensões e guardrails construídos pela comunidade', es: 'Agentes, extensiones y guardrails construidos por la comunidad', fr: 'Agents, extensions et guardrails développés par la communauté', de: 'Von der Community entwickelte Agenten, Erweiterungen und Guardrails', ja: 'コミュニティが作成したエージェント、拡張機能、ガードレール', ko: '커뮤니티가 구축한 에이전트, 확장, 가드레일', zh: '社区构建的智能体、扩展和护栏' },
  'about.license.footer': { pt: 'AgentOS é open source sob a licença Apache 2.0. Para suporte empresarial e deployments de produção, contate-nos em <link>team@frame.dev</link>.', es: 'AgentOS es open source bajo la licencia Apache 2.0. Para soporte empresarial y despliegues en producción, contáctanos en <link>team@frame.dev</link>.', fr: 'AgentOS est open source sous licence Apache 2.0. Pour le support entreprise et les déploiements en production, contactez-nous à <link>team@frame.dev</link>.', de: 'AgentOS ist Open Source unter der Apache-2.0-Lizenz. Für Enterprise-Support und Produktions-Deployments kontaktiere uns unter <link>team@frame.dev</link>.', ja: 'AgentOS は Apache 2.0 ライセンスのオープンソースです。エンタープライズサポートと本番デプロイについては <link>team@frame.dev</link> までお問い合わせください。', ko: 'AgentOS는 Apache 2.0 라이선스 하의 오픈소스입니다. 엔터프라이즈 지원 및 프로덕션 배포는 <link>team@frame.dev</link>로 연락해 주세요.', zh: 'AgentOS 是采用 Apache 2.0 许可证的开源项目。如需企业支持和生产部署,请通过 <link>team@frame.dev</link> 联系我们。' },
