  // ---------- benchmarks ----------
  'benchmarks.badge': { pt: 'SOTA · LongMemEval · LOCOMO · Phase B N=500', es: 'SOTA · LongMemEval · LOCOMO · Phase B N=500', fr: 'SOTA · LongMemEval · LOCOMO · Phase B N=500', de: 'SOTA · LongMemEval · LOCOMO · Phase B N=500', ja: 'SOTA · LongMemEval · LOCOMO · Phase B N=500', ko: 'SOTA · LongMemEval · LOCOMO · Phase B N=500', zh: 'SOTA · LongMemEval · LOCOMO · Phase B N=500' },
  'benchmarks.title': { pt: 'Benchmarks de Memória com Reader Equivalente', es: 'Benchmarks de Memoria con Reader Equivalente', fr: 'Benchmarks Mémoire à Reader Équivalent', de: 'Memory-Benchmarks mit identischem Reader', ja: '同一リーダーでのメモリベンチマーク', ko: '동일 리더로 측정한 메모리 벤치마크', zh: '在匹配读取器下的记忆基准' },
  'benchmarks.subtitle': { pt: 'Comparação honesta e direta: mesmo reader gpt-4o, mesmo dataset, mesma metodologia Phase B N=500, mesmo juiz gpt-4o-2024-08-06 com rubric 2026-04-18.1. Configurações cross-provider são excluídas porque não podem ser reproduzidas a partir das divulgações de metodologia pública.', es: 'Comparación honesta y directa: mismo reader gpt-4o, mismo dataset, misma metodología Phase B N=500, mismo juez gpt-4o-2024-08-06 con rubric 2026-04-18.1. Las configuraciones cross-provider se excluyen porque no se pueden reproducir desde las divulgaciones de metodología pública.', fr: 'Comparaison honnête et équitable : même reader gpt-4o, même dataset, même méthodologie Phase B N=500, même juge gpt-4o-2024-08-06 avec rubrique 2026-04-18.1. Les configurations cross-provider sont exclues car elles ne peuvent pas être reproduites à partir des divulgations méthodologiques publiques.', de: 'Ehrlicher Apples-to-Apples-Vergleich: gleicher gpt-4o-Reader, gleicher Datensatz, gleiche Phase-B-N=500-Methodik, gleicher gpt-4o-2024-08-06-Richter mit Rubric 2026-04-18.1. Cross-Provider-Konfigurationen sind ausgeschlossen, weil sie aus öffentlichen Methodikangaben nicht reproduzierbar sind.', ja: '正直で公正な比較:同じ gpt-4o リーダー、同じデータセット、同じ Phase B N=500 方法論、同じ gpt-4o-2024-08-06 ジャッジ、同じルーブリック 2026-04-18.1。クロスプロバイダ構成は、公開された方法論の開示から再現できないため除外されています。', ko: '정직한 동등 비교: 동일한 gpt-4o 리더, 동일한 데이터셋, 동일한 Phase B N=500 방법론, 동일한 gpt-4o-2024-08-06 판단자, 동일한 루브릭 2026-04-18.1. 크로스 프로바이더 구성은 공개된 방법론 공시에서 재현할 수 없기 때문에 제외됩니다.', zh: '诚实的同基准对比:相同的 gpt-4o 读取器、相同的数据集、相同的 Phase B N=500 方法、相同的 gpt-4o-2024-08-06 裁判、相同的评分准则 2026-04-18.1。跨提供商配置因无法从公开方法论披露中复现而被排除。' },
  'benchmarks.tabS': { pt: 'LongMemEval-S (115K tokens)', es: 'LongMemEval-S (115K tokens)', fr: 'LongMemEval-S (115K tokens)', de: 'LongMemEval-S (115K Tokens)', ja: 'LongMemEval-S (115K トークン)', ko: 'LongMemEval-S (115K 토큰)', zh: 'LongMemEval-S (115K 个 token)' },
  'benchmarks.tabM': { pt: 'LongMemEval-M (1.5M tokens)', es: 'LongMemEval-M (1.5M tokens)', fr: 'LongMemEval-M (1,5M tokens)', de: 'LongMemEval-M (1,5M Tokens)', ja: 'LongMemEval-M (1.5M トークン)', ko: 'LongMemEval-M (1.5M 토큰)', zh: 'LongMemEval-M (1.5M 个 token)' },
