  'benchmarks.highlightSCi': { pt: '[82.4%, 88.6%] · $0,0090/correta · 4 segundos de latência média', es: '[82.4%, 88.6%] · $0,0090/correcta · 4 segundos de latencia media', fr: '[82,4 %, 88,6 %] · 0,0090 $/correcte · 4 secondes de latence moyenne', de: '[82,4 %, 88,6 %] · 0,0090 $/korrekt · 4 Sekunden durchschnittliche Latenz', ja: '[82.4%, 88.6%] · $0.0090/正解 · 平均レイテンシ 4 秒', ko: '[82.4%, 88.6%] · 정답당 $0.0090 · 평균 지연 4초', zh: '[82.4%, 88.6%] · 每条正确 $0.0090 · 平均延迟 4 秒' },
  'benchmarks.highlightMAccuracy': { pt: 'AgentOS LongMemEval-M', es: 'AgentOS LongMemEval-M', fr: 'AgentOS LongMemEval-M', de: 'AgentOS LongMemEval-M', ja: 'AgentOS LongMemEval-M', ko: 'AgentOS LongMemEval-M', zh: 'AgentOS LongMemEval-M' },
  'benchmarks.highlightMValue': { pt: '70.2%', es: '70.2%', fr: '70,2%', de: '70,2%', ja: '70.2%', ko: '70.2%', zh: '70.2%' },
  'benchmarks.highlightMCi': { pt: '[66.0%, 74.0%] · Primeira biblioteca open source acima de 65% na variante de 1,5M tokens', es: '[66.0%, 74.0%] · Primera librería open source por encima del 65% en la variante de 1,5M tokens', fr: '[66,0 %, 74,0 %] · Première bibliothèque open source au-dessus de 65 % sur la variante 1,5M tokens', de: '[66,0 %, 74,0 %] · Erste Open-Source-Bibliothek über 65 % bei der 1,5M-Token-Variante', ja: '[66.0%, 74.0%] · 1.5M トークンバリアントで 65% を超えた最初のオープンソースライブラリ', ko: '[66.0%, 74.0%] · 1.5M 토큰 변형에서 65%를 넘은 최초의 오픈소스 라이브러리', zh: '[66.0%, 74.0%] · 在 1.5M token 变体上首个超过 65% 的开源库' },
  'benchmarks.matrixIntro': { pt: 'Reader gpt-4o equivalente, Phase B N=500. Os CIs de bootstrap usam 10.000 reamostragens Mulberry32 com seed=42.', es: 'Reader gpt-4o equivalente, Phase B N=500. Los CIs de bootstrap usan 10.000 remuestreos Mulberry32 con seed=42.', fr: 'Reader gpt-4o équivalent, Phase B N=500. Les IC bootstrap utilisent 10 000 ré-échantillonnages Mulberry32 avec seed=42.', de: 'Identischer gpt-4o-Reader, Phase B N=500. Bootstrap-CIs verwenden 10.000 Mulberry32-Resampling mit seed=42.', ja: '同一 gpt-4o リーダー、Phase B N=500。Bootstrap CI は seed=42 で 10,000 回の Mulberry32 リサンプリングを使用。', ko: '동일한 gpt-4o 리더, Phase B N=500. 부트스트랩 CI는 seed=42로 10,000회의 Mulberry32 재샘플링을 사용합니다.', zh: '匹配的 gpt-4o 读取器,Phase B N=500。Bootstrap 置信区间使用 seed=42 的 10,000 次 Mulberry32 重采样。' },
  'benchmarks.ctaReadAudit': { pt: 'Ler a Auditoria de Transparência', es: 'Leer la Auditoría de Transparencia', fr: 'Lire l’Audit de Transparence', de: 'Transparenz-Audit lesen', ja: 'トランスペアレンシー監査を読む', ko: '투명성 감사 읽기', zh: '阅读透明度审计' },
  'benchmarks.ctaSeeRunJsons': { pt: 'Ver os JSONs de execução no GitHub', es: 'Ver los JSONs de ejecución en GitHub', fr: 'Voir les JSON d’exécution sur GitHub', de: 'Run-JSONs auf GitHub ansehen', ja: '実行 JSON を GitHub で見る', ko: 'GitHub에서 실행 JSON 보기', zh: '在 GitHub 上查看运行 JSON' },
  'benchmarks.ctaBenchmarksPage': { pt: 'Referência Completa de Benchmarks', es: 'Referencia Completa de Benchmarks', fr: 'Référence Complète des Benchmarks', de: 'Vollständige Benchmark-Referenz', ja: 'ベンチマーク完全リファレンス', ko: '벤치마크 전체 레퍼런스', zh: '完整基准参考' },
  'benchmarks.footnote': { pt: 'Mastra OM 94,9%, Mem0 v3 93,4%, Hindsight 91,4%, agentmemory 96,2% e Supermemory 85,2% todos usam readers cross-provider (gpt-5-mini, gemini-3-pro) ou infraestrutura de plataforma gerenciada onde o modelo do juiz, rubric e seed subjacentes não são publicados. A comparação com reader equivalente acima é o que pode ser reproduzido independentemente a partir da metodologia que cada vendor divulga.', es: 'Mastra OM 94,9%, Mem0 v3 93,4%, Hindsight 91,4%, agentmemory 96,2% y Supermemory 85,2% usan readers cross-provider (gpt-5-mini, gemini-3-pro) o infraestructura de plataforma gestionada donde el modelo del juez, rubric y seed subyacentes no se publican. La comparación con reader equivalente anterior es lo que se puede reproducir de forma independiente a partir de la metodología que cada vendor divulga.', fr: 'Mastra OM 94,9%, Mem0 v3 93,4%, Hindsight 91,4%, agentmemory 96,2% et Supermemory 85,2% utilisent tous des readers cross-provider (gpt-5-mini, gemini-3-pro) ou une infrastructure de plateforme gérée où le modèle du juge, la rubrique et le seed sous-jacents ne sont pas publiés. La comparaison à reader équivalent ci-dessus est ce qui peut être reproduit indépendamment à partir de la méthodologie divulguée par chaque vendor.', de: 'Mastra OM 94,9%, Mem0 v3 93,4%, Hindsight 91,4%, agentmemory 96,2% und Supermemory 85,2% nutzen allesamt Cross-Provider-Reader (gpt-5-mini, gemini-3-pro) oder Managed-Platform-Infrastruktur, bei der das zugrundeliegende Richter-Modell, die Rubric und der Seed nicht veröffentlicht werden. Der Vergleich mit identischem Reader oben ist das, was sich aus der von jedem Anbieter offengelegten Methodik unabhängig reproduzieren lässt.', ja: 'Mastra OM 94.9%、Mem0 v3 93.4%、Hindsight 91.4%、agentmemory 96.2%、Supermemory 85.2% はすべてクロスプロバイダのリーダー(gpt-5-mini、gemini-3-pro)またはマネージドプラットフォームのインフラを使用しており、基礎となるジャッジモデル、ルーブリック、シードが公開されていません。上記の同一リーダーでの比較は、各ベンダが開示する方法論から独立して再現可能なものです。', ko: 'Mastra OM 94.9%, Mem0 v3 93.4%, Hindsight 91.4%, agentmemory 96.2%, Supermemory 85.2%는 모두 크로스 프로바이더 리더(gpt-5-mini, gemini-3-pro) 또는 관리형 플랫폼 인프라를 사용하며, 그 아래 판단자 모델, 루브릭, 시드가 공개되지 않습니다. 위의 동일 리더 비교는 각 벤더가 공개한 방법론에서 독립적으로 재현 가능한 부분입니다.', zh: 'Mastra OM 94.9%、Mem0 v3 93.4%、Hindsight 91.4%、agentmemory 96.2% 和 Supermemory 85.2% 都使用了跨提供商读取器(gpt-5-mini、gemini-3-pro)或托管平台基础设施,其底层裁判模型、评分准则与种子均未公开。上方的匹配读取器对比是从每个供应商公开的方法论中可独立复现的部分。' },
